const targetX = args.x;
const targetZ = args.z;
const radius = args.radius;
const targetY = bot.entity.position.y;

startBackgroundSkill(bot, 'move_to_midpoint', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);
  const goal = new goals.GoalNear(targetX, targetY, targetZ, radius);

  try {
    await bot.pathfinder.goto(goal);
    if (!token.cancelled) {
      console.log('Successfully reached midpoint vicinity.');
    }
  } catch (error) {
    if (!token.cancelled) {
      console.log('Pathfinder error or movement interrupted: ' + error.message);
    }
  }
});

return "<MOVING>: Moving toward midpoint (" + targetX + ", " + targetZ + ") with a radius of " + radius + ".";
